// 🔹 handleActionPropriete
// - Gère les actions du tableau des propriétés
// - Stocke la propriété sélectionnée dans flow.propSelected
// Gestion des actions du tableau des propriétés

if (msg.topic === "propriete_action") {
    let action = msg.payload.action;
    let prop = msg.payload.propriete;
    let varSelected = flow.get("varSelected");

    // Vérifie qu'une action et une ligne sont sélectionnées
    if (!action || !prop) {
        msg.info = "⚠️ Aucune action ou ligne sélectionnée.";
        return null;
    }

    // Stocke la propriété sélectionnée
    flow.set("propSelected", prop);

    // Détermine le topic en fonction de l'action
    switch (action) {
        case "edit":
            msg.topic = "editBasePropriete";
            msg.info = `✏️ Édition de la propriété "${prop.nomP}".`;
            break;
        case "supprimer":
            msg.topic = "deletePropriete";
            msg.info = `❌ Suppression de la propriété "${prop.nomP}".`;
            break;
        case "valeur":
            msg.topic = "editValeursPropriete";
            msg.info = `📝 Édition des valeurs pour "${prop.nomP}".`;
            break;
        case "schema":
            msg.topic = "editSchemaPropriete";
            msg.info = `🔧 Édition du schéma pour "${prop.nomP}".`;
            break;
        default:
            msg.topic = "unknown";
            msg.info = `⚠️ Action "${action}" non reconnue.`;
    }

    // Envoie la ligne sélectionnée
    msg.payload = prop;
    return msg;
} else {
    return null;
}

// 🔹 formulaireBasePropriete
// - Prépare le formulaire pour éditer une propriété

// Récupère la propriété sélectionnée depuis le message (et non depuis le flow)
let prop = msg.payload.propriete || {};
let varSelected = flow.get("varSelected");

// Vérifie qu'une propriété est sélectionnée
if (!prop || !prop.nomP) {
    msg.info = "⚠️ Aucune propriété sélectionnée.";
    return null;
}

// Stocke la propriété sélectionnée dans le flow context
flow.set("propSelected", prop);

// Prépare les données du formulaire
msg.payload = {
    nomP: prop.nomP || "",
    abbrP: prop.abbrP || "",
    typeP: prop.typeP || "string",
    schema: prop.schemaP ? JSON.stringify(prop.schemaP, null, 2) : ""  // Convertit le schéma en chaîne JSON formatée
};

// Ajoute les options de type pour le dropdown
msg.dropdownOptions = [
    { dropdown: "typeP", value: "string", label: "Texte (string)" },
    { dropdown: "typeP", value: "number", label: "Nombre (number)" },
    { dropdown: "typeP", value: "boolean", label: "Booléen (boolean)" },
    { dropdown: "typeP", value: "array", label: "Tableau (array)" },
    { dropdown: "typeP", value: "object", label: "Objet (object)" }
];

msg.info = `📋 Chargement du formulaire pour "${prop.nomP}".`;
return msg;

// 🔹 supprimerPropriete
// - Supprime une propriété de la variable sélectionnée

let propSelected = flow.get("propSelected") || {};
let varSelected = flow.get("varSelected");
let enrichedVars = global.get("enrichedVars", "file") || {};

// Vérifie qu'une propriété est sélectionnée
if (!propSelected.nomP || !varSelected) {
    msg.info = "⚠️ Aucune propriété ou variable sélectionnée.";
    return null;
}

// Récupère la variable et ses propriétés
let variable = enrichedVars[varSelected] || {};
let proprietes = variable.proprietes || [];
let index = proprietes.findIndex(p => p.nomP === propSelected.nomP);

// Supprime la propriété
if (index >= 0) {
    proprietes.splice(index, 1);
    enrichedVars[varSelected].proprietes = proprietes;
    global.set("enrichedVars", enrichedVars, "file");

    // Réinitialise propSelected
    flow.set("propSelected", null);

    msg.topic = "refreshTableauProprietes";
    msg.info = `✅ Propriété "${propSelected.nomP}" supprimée.`;
} else {
    msg.info = "❌ Propriété introuvable.";
}

return msg;

// 🔹 prepareEditeurValeurs
let propSelected = flow.get("propSelected") || {};
let varSelected = flow.get("varSelected");
let enrichedVars = global.get("enrichedVars", "file") || {};
let variable = enrichedVars[varSelected] || {};
let instances = variable.instances || ["*"];

// Vérifie qu'une propriété est sélectionnée
if (!propSelected.nomP) {
    msg.info = "⚠️ Aucune propriété sélectionnée.";
    return null;
}

// Prépare les valeurs pour chaque instance
let valeurs = propSelected.valeurs || {};
let valeursInstances = instances.map(inst => ({
    instance: inst,
    valeur: valeurs[inst] !== undefined ? valeurs[inst] : null,
    type: propSelected.typeP
}));

// Envoie au template
msg.payload = {
    nomPropriete: propSelected.nomP,
    typePropriete: propSelected.typeP,
    valeursInstances,
    schema: propSelected.schema || null
};

msg.info = `📝 Édition des valeurs de "${propSelected.nomP}" (Type: ${propSelected.typeP}).`;
return msg;

// 🔹 formulaireEditeurSchema
// - Prépare le formulaire pour éditer le schéma d'une propriété

// Récupère la propriété depuis le message (et non depuis le flow)
let prop = msg.payload.propriete || {};

// Vérifie que la propriété est de type object ou array
if (prop.typeP !== "object" && prop.typeP !== "array") {
    msg.info = "⚠️ Cette propriété n'est pas de type 'object' ou 'array'.";
    return null;
}

// Prépare les sous-propriétés pour le formulaire
let sousProprietes = [];
if (prop.schema) {
    if (Array.isArray(prop.schema)) {
        sousProprietes = prop.schema.map(item => ({
            nom: item.nomSsP || item.nom,
            type: item.typeSsP || item.type
        }));
    } else if (typeof prop.schemaP === 'object') {
        sousProprietes = Object.entries(prop.schemaP).map(([nom, type]) => ({
            nom: nom,
            type: type
        }));
    }
}

// Envoie les données du formulaire
msg.payload = {
    nomPropriete: prop.nomP,
    typePropriete: prop.typeP,
    sousProprietes: sousProprietes
};

msg.info = `🔧 Chargement de l'éditeur de schéma pour "${prop.nomP}".`;
return msg;

// 🔹 sauvegarderPropriete
// - Sauvegarde les modifications d'une propriété

let formData = msg.payload;
let varSelected = flow.get("varSelected");
let propSelected = flow.get("propSelected");
let enrichedVars = global.get("enrichedVars", "file") || {};

// Vérifie les données du formulaire
if (!formData || !formData.nomP || !varSelected) {
    msg.info = "❌ Données du formulaire incomplètes.";
    return null;
}

// Parse le schéma si c'est une chaîne JSON
let schemaParsed = null;
if (formData.schema && typeof formData.schema === 'string' && formData.schema.trim() !== "") {
    try {
        schemaParsed = JSON.parse(formData.schema);
    } catch (e) {
        node.warn("Erreur de parsing du schéma: " + e.message);
        schemaParsed = null;
    }
}

// Récupère la variable et ses propriétés
let variable = enrichedVars[varSelected] || {};
let proprietes = variable.proprietes || [];
let index = proprietes.findIndex(p => p.nomP === propSelected.nomP);

// Met à jour ou ajoute la propriété
if (index >= 0) {
    // Met à jour la propriété existante
    proprietes[index] = {
        ...proprietes[index],
        nomP: formData.nomP,
        abbrP: formData.abbrP,
        typeP: formData.typeP,
        schemaP: schemaParsed
    };
} else {
    // Ajoute une nouvelle propriété
    proprietes.push({
        nomP: formData.nomP,
        abbrP: formData.abbrP,
        typeP: formData.typeP,
        schemaP: schemaParsed,
        valeurs: { "*": null } // Valeur par défaut
    });
}

// Met à jour la variable
enrichedVars[varSelected].proprietes = proprietes;
global.set("enrichedVars", enrichedVars, "file");

// Met à jour flow.propSelected
flow.set("propSelected", {
    nomP: formData.nomP,
    abbrP: formData.abbrP,
    typeP: formData.typeP,
    schemaP: schemaParsed,
    valeurs: proprietes[index >= 0 ? index : proprietes.length - 1].valeurs
});

// Envoie une confirmation et déclenche le rafraîchissement
msg.topic = "refreshTableauProprietes";
msg.info = `✅ Propriété "${formData.nomP}" sauvegardée.`;
msg.payload = {
    action: "refresh",
    varSelected: varSelected
};
return msg;

// 🔹 sauvegarderSchema
// - Sauvegarde le schéma modifié pour une propriété

let formData = msg.payload;
let varSelected = flow.get("varSelected");
let propSelected = flow.get("propSelected");
let enrichedVars = global.get("enrichedVars", "file") || {};

// Vérifie les données
if (!formData || !varSelected || !propSelected) {
    msg.info = "❌ Données incomplètes.";
    return null;
}

// Construit le schéma à partir des sous-propriétés
let newSchema = {};
if (formData.sousProprietes) {
    formData.sousProprietes.forEach(sp => {
        if (sp.nom) {
            newSchema[sp.nom] = sp.type;
        }
    });
}

// Récupère la variable et ses propriétés
let variable = enrichedVars[varSelected] || {};
let proprietes = variable.proprietes || [];
let index = proprietes.findIndex(p => p.nomP === propSelected.nomP);

// Met à jour le schéma
if (index >= 0) {
    // Pour les objets, on transforme en tableau de sous-propriétés
    if (propSelected.typeP === "object") {
        proprietes[index].schema = Object.entries(newSchema).map(([nom, type]) => ({
            nomSsP: nom,
            typeSsP: type
        }));
    }
    // Pour les arrays, on garde le schéma sous forme d'objet
    else if (propSelected.typeP === "array") {
        proprietes[index].schema = newSchema;
    }

    // Met à jour enrichedVars
    enrichedVars[varSelected].proprietes = proprietes;
    global.set("enrichedVars", enrichedVars, "file");

    // Met à jour flow.propSelected
    flow.set("propSelected", {
        ...propSelected,
        schema: propSelected.typeP === "object"
            ? Object.entries(newSchema).map(([nom, type]) => ({ nomSsP: nom, typeSsP: type }))
            : newSchema
    });

    msg.topic = "refreshTableauProprietes";
    msg.info = `✅ Schéma de "${propSelected.nomP}" mis à jour.`;
} else {
    msg.info = "❌ Propriété introuvable.";
}

return msg;

// 🔹 sauvegarderValeurs
let formData = msg.payload;
let varSelected = flow.get("varSelected");
let propSelected = flow.get("propSelected");
let enrichedVars = global.get("enrichedVars", "file") || {};

if (!formData || !varSelected || !propSelected) {
    msg.info = "❌ Données incomplètes.";
    return null;
}

let variable = enrichedVars[varSelected] || {};
let proprietes = variable.proprietes || [];
let index = proprietes.findIndex(p => p.nomP === propSelected.nomP);

if (index >= 0) {
    let valeurs = {};
    formData.valeursInstances.forEach(vi => {
        valeurs[vi.instance] = vi.valeur;
    });
    proprietes[index].valeurs = valeurs;

    enrichedVars[varSelected].proprietes = proprietes;
    global.set("enrichedVars", enrichedVars, "file");

    flow.set("propSelected", {
        ...propSelected,
        valeurs: valeurs
    });

    msg.topic = "refreshTableauProprietes";
    msg.info = `✅ Valeurs de "${propSelected.nomP}" mises à jour.`;
} else {
    msg.info = "❌ Propriété introuvable.";
}

return msg;

// 🔹 prepareTableauProprietes (version dynamique pour ui-template)

// 1. Variable sélectionnée dans le flow context
let varSelected = flow.get("varSelected") || null;

// 2. Lecture des enrichedVars depuis le global.json (stocké avec scope "file")
let enrichedVars = global.get("enrichedVars", "file") || {};

// 3. Variable correspondante
let variable = enrichedVars[varSelected] || null;

// 4. Vérification : variable valide ?
if (!varSelected || !variable) {
    msg.payload = {
        variable: {
            nomVarG: "",
            descriptionVarG: "",
            instances: [],
            proprietes: []
        }
    };
    msg.info = "⚠️ Aucune variable sélectionnée ou variable introuvable.";
    return msg;
}

// 5. Préparation du payload pour le ui-template
msg.payload = {
    variable: {
        nomVarG: variable.nomVarG,
        abbrVarG: variable.abbrVarG,
        descriptionVarG: variable.descriptionVarG,
        dateUpdateVarG: variable.dateUpdateVarG,
        instances: variable.instances || ["*"],
        proprietes: (variable.proprietes || []).map(p => ({
            nomP: p.nomP,
            abbrP: p.abbrP,
            typeP: p.typeP,
            schema: p.schema,
            valeurs: p.valeurs
        }))
    }
};

msg.info = `✅ Variable sélectionnée : ${varSelected}`;
return msg;

// Gestionnaire centralisé des actions du tableau
//Vérifie que le message contient une action
if (msg.topic === "propriete_action" && msg.payload) {
    let action = msg.payload.action;
    let prop = msg.payload.propriete;

    // Stocke la propriété sélectionnée dans le flow context
    flow.set("propSelected", prop);
    // Transmet l'action et la propriété
    msg.payload = {
        action: action,
        propriete: prop
     };
     return msg;
    }
 else {
    // Si ce n'est pas une action valide, retourne null
    return null;
     }
